function WebPanel() {
  const [url, setUrl] = React.useState('REPLACE_WITH_URL');
  const [input, setInput] = React.useState('REPLACE_WITH_URL');
  const [error, setError] = React.useState(false);

  const go = () => {
    let u = input.trim();
    if (!u) return;
    if (!u.startsWith('http')) u = 'https://' + u;
    setUrl(u);
    setError(false);
  };

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100%',fontFamily:'system-ui'}}>
      <div style={{display:'flex',gap:8,padding:'8px 12px',background:'#f5f5f5',borderBottom:'1px solid #ddd'}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==='Enter'&&go()}
          style={{flex:1,padding:'6px 10px',borderRadius:6,border:'1px solid #ccc',fontSize:13}}
          placeholder="Enter URL…"/>
        <button onClick={go}
          style={{padding:'6px 14px',borderRadius:6,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer',fontSize:13}}>
          Go
        </button>
        <a href={url} target="_blank" rel="noopener noreferrer"
          style={{padding:'6px 10px',borderRadius:6,background:'#fff',border:'1px solid #ccc',fontSize:13,color:'#333',textDecoration:'none'}}>
          ↗ Open
        </a>
      </div>
      <div style={{flex:1,position:'relative'}}>
        <iframe
          src={url}
          style={{width:'100%',height:'100%',border:'none'}}
          onError={()=>setError(true)}
          sandbox="allow-scripts allow-same-origin allow-forms allow-popups"
        />
        {error && (
          <div style={{position:'absolute',inset:0,display:'flex',alignItems:'center',justifyContent:'center',background:'#fff',padding:20}}>
            <div style={{textAlign:'center'}}>
              <div style={{fontSize:18,fontWeight:600,marginBottom:8}}>This site blocks framing</div>
              <div style={{color:'#888',marginBottom:12}}>Try opening in a new tab instead.</div>
              <a href={url} target="_blank" rel="noopener noreferrer"
                style={{padding:'8px 16px',borderRadius:8,background:'#007AFF',color:'#fff',textDecoration:'none',display:'inline-block'}}>
                Open {url}
              </a>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
render(<WebPanel/>);
